mapper.update:
UPDATE social_activities SET
visibility = #{visibility},
is_active = #{isActive}
WHERE id = #{id}

mapper.select:
,
CASE WHEN #{currentUserId, jdbcType=BIGINT} IS NOT NULL THEN
EXISTS(SELECT 1 FROM activity_likes al
WHERE al.activity_id = sa.id AND al.user_id = #{currentUserId, jdbcType=BIGINT})
ELSE FALSE END AS is_liked_by_me
FROM social_activities sa
JOIN users u ON u.id = sa.user_id
LEFT JOIN user_social_profiles sp ON sp.user_id = sa.user_id
WHERE sa.user_id = #{profileUserId}
AND sa.is_active = TRUE
AND (
sa.visibility = 'public'
OR (sa.visibility = 'followers' AND #{currentUserId, jdbcType=BIGINT} IS NOT NULL AND EXISTS(
SELECT 1 FROM user_follows
WHERE follower_id = #{currentUserId, jdbcType=BIGINT} AND following_id = #{profileUserId}
))
OR sa.user_id = #{currentUserId, jdbcType=BIGINT}
)
ORDER BY sa.created_at DESC
LIMIT #{limit} OFFSET #{offset}
